parameters.jsCode:
// Process crawl4ai response and prepare for chunking
const input = $input.first().json;

// Extract content from crawl4ai response
let extractedContent = '';
let title = '';
let url = '';
let metadata = {};

if (input.results && input.results.length > 0) {
  const result = input.results[0];
  extractedContent = result.extracted_content || result.markdown || result.cleaned_html || '';
  title = result.title || 'Untitled';
  url = result.url || $('webhook-trigger').first().json.url;
  metadata = {
    success: result.success,
    status_code: result.status_code,
    media: result.media || [],
    links: result.links || [],
    screenshot: result.screenshot
  };
} else {
  throw new Error('No content extracted from crawl4ai');
}

// Simple text chunking (can be improved)
const chunkSize = 1000;
const chunkOverlap = 200;
const chunks = [];

if (extractedContent.length > chunkSize) {
  for (let i = 0; i < extractedContent.length; i += chunkSize - chunkOverlap) {
    const chunk = extractedContent.slice(i, i + chunkSize);
    chunks.push({
      content: chunk,
      chunk_index: Math.floor(i / (chunkSize - chunkOverlap)),
      start_pos: i,
      end_pos: Math.min(i + chunkSize, extractedContent.length)
    });
  }
} else {
  chunks.push({
    content: extractedContent,
    chunk_index: 0,
    start_pos: 0,
    end_pos: extractedContent.length
  });
}

// Return document info and chunks
return {
  json: {
    document: {
      title: title,
      source_type: 'web',
      source_url: url,
      content_length: extractedContent.length,
      chunk_count: chunks.length,
      metadata: metadata,
      processing_timestamp: new Date().toISOString()
    },
    chunks: chunks
  }
};

